func TestGetCloseOrderInput(t *testing.T) {
	data, err := GetCloseOrderInput(
		new(big.Int).SetUint64(1111),
		new(big.Int).SetUint64(122),
		new(big.Int).SetUint64(123),
		"BTCUSDT")
	if err != nil {
		t.Error(err)
		return
	}
	t.Log(data)
	t.Log(hexutil.Encode(data))
}

