func TestUrlContractSignOwner(t *testing.T) {
	//配置变量
	os.Setenv("Apikey", "dtcd_xxxxxx")
	os.Setenv("BaseUrl", "http://47.111.28.25:8016")
	os.Setenv("KeyId", "0a1382ae-7e21-49e8-928e-0614103b2045")
	os.Setenv("OwnerAddress", "0x5D001706b0b4bF6a0D5C234E1F966D82D3C84F92")
	os.Setenv("RpcUrl", "http://ec2-54-251-227-86.ap-southeast-1.compute.amazonaws.com:6979")
	//os.Setenv("XApiKey", "")
	os.Setenv("HmacKey", "hmac")
	os.Setenv("ContractAddr", "0x0d7a5cD806536Fa7c3bA8f580D7dB7144253dE4a")

	headerKey := os.Getenv("Apikey")
	if headerKey == "" {
		return
	}
	conf.Apikey = headerKey
	BaseUrl := os.Getenv("BaseUrl")
	if BaseUrl == "" {
		return
	}
	conf.BaseUrl = BaseUrl
	KeyId := os.Getenv("KeyId")
	if KeyId == "" {
		return
	}
	conf.KeyId = KeyId
	OwnerAddress := os.Getenv("OwnerAddress")
	if OwnerAddress == "" {
		return
	}
	conf.OwnerAddress = OwnerAddress
	HmacKey := os.Getenv("HmacKey")
	if HmacKey == "" {
		return
	}
	conf.HmacKey = HmacKey
	ContractAddr := os.Getenv("ContractAddr")
	if ContractAddr == "" {
		return
	}
	conf.ContractBztAddr = ContractAddr
	//初始化节点
	conf.RpcUrl = os.Getenv("RpcUrl")
	if conf.RpcUrl == "" {
		return
	}
	log.Info("rpc url is ", conf.RpcUrl)
	var err error
	Client, err := InitEthClient(conf.RpcUrl)
	if err != nil {
		return
	}
	orderId := new(big.Int).SetUint64(5)
	amount := new(big.Int).SetUint64(1000000)
	input, err := GetOpenOrderInput(orderId, "BTCUSDT", amount)
	if err != nil {
		t.Fatalf("GetOpenOrderInput err: %s", err)
		return
	}
	a, b, err := UrlContractSignOwner(input, Client)
	if err != nil {
		t.Fatalf("UrlContractSignOwner err: %s", err)
		return
	}
	t.Log(a)
	t.Log(b)
}

